jsonata:
(
  $active := [lines[status != "cancelled"]];
  {
    "documentType": documentType,
    "orderId": orderId,
    "partner": $uppercase(partner),
    "partnerName": ($n := $lookup({"ACME": "ACME Industrial Corp.", "GLOBEX": "Globex Corporation"}, $uppercase(partner)); $exists($n) ? $n : partner),
    "orderDate": orderDate,
    "lines": [$active.{
      "sku": sku,
      "description": description,
      "quantity": quantity,
      "unitPrice": unitPrice,
      "lineTotal": $round(quantity * unitPrice, 2)
    }],
    "totals": {
      "lineCount": $count($active),
      "quantity": $sum($active.quantity),
      "amount": $round($sum($active.(quantity * unitPrice)), 2)
    }
  }
)
